MOD = 998244353
PRIMITIVE_ROOT = 3

def pow_mod(base, exp, mod):
    res = 1
    base %= mod
    while exp > 0:
        if exp % 2 == 1:
            res = (res * base) % mod
        base = (base * base) % mod
        exp //= 2
    return res

def inv_mod(n, mod):
    return pow_mod(n, mod - 2, mod)

def ntt(a, inverse=False):
    n = len(a)

    j = 0
    for i in range(n):
        if i < j:
            a[i], a[j] = a[j], a[i]

        bit = n >> 1
        while bit > 0 and (j & bit):
            j ^= bit
            bit >>= 1
        j ^= bit

    len_stage = 2
    while len_stage <= n:

        root_of_unity_for_stage = pow_mod(PRIMITIVE_ROOT, (MOD - 1) // len_stage, MOD)
        if inverse:
            root_of_unity_for_stage = inv_mod(root_of_unity_for_stage, MOD)

        for i in range(0, n, len_stage):
            w = 1
            for j in range(len_stage // 2):
                u = a[i + j]
                v = (a[i + j + len_stage // 2] * w) % MOD
                a[i + j] = (u + v) % MOD
                a[i + j + len_stage // 2] = (u - v + MOD) % MOD
                w = (w * root_of_unity_for_stage) % MOD

        len_stage *= 2

    if inverse:
        inv_n = inv_mod(n, MOD)
        for i in range(n):
            a[i] = (a[i] * inv_n) % MOD

    return a
